// Before (buggy):
function formatDate(date: Date): string {
  const month = date.getMonth();
  const day = date.getDate();
  const year = date.getFullYear();
  return `${month}/${day}/${year}`;
}

// After (fixed):
function formatDate(date: Date): string {
  const month = date.getMonth() + 1;
  const day = date.getDate();
  const year = date.getFullYear();
  return `${month}/${day}/${year}`;
}

// .claude/settings.json
{
  "hooks": {
    "preCommit": [
      {
        "command": "npm run lint",
        "description": "Run ESLint and Prettier checks"
      },
      {
        "command": "npm test -- --bail",
        "description": "Run test suite, stop on first failure"
      }
    ],
    "postFileEdit": [
      {
        "command": "npx tsc --noEmit --pretty",
        "description": "Type-check after file edits"
      }
    ]
  },
  "permissions": {
    "allow": [
      "Bash(npm run *)",
      "Bash(npx prisma *)",
      "Bash(npx tsc *)",
      "Read(*)",
      "Write(src/**)",
      "Write(tests/**)"
    ],
    "deny": [
      "Write(.env*)",
      "Write(prisma/migrations/**)",
      "Bash(rm -rf *)",
      "Bash(git push *)"
    ]
  }
}

